import{_ as i,W as l,X as p,$ as s,a0 as n,a1 as e,Y as o,Z as t,D as c}from"./framework-805da640.js";const r={},d=s("h1",{id:"简介",tabindex:"-1"},[s("a",{class:"header-anchor",href:"#简介","aria-hidden":"true"},"#"),n(" 简介")],-1),u=s("figure",null,[s("img",{src:"https://minio.kevin2li.top/image-bed/vanblog/img/901aaaa32b73193420138a46953eb05c.20221113203003.png",alt:"",tabindex:"0",loading:"lazy"}),s("figcaption")],-1),m={href:"https://github.com/rustdesk/rustdesk",target:"_blank",rel:"noopener noreferrer"},k=s("br",null,null,-1),b={href:"https://rustdesk.com/zh/",target:"_blank",rel:"noopener noreferrer"},v=t(`<h1 id="背景" tabindex="-1"><a class="header-anchor" href="#背景" aria-hidden="true">#</a> 背景</h1><p>之所以选择这款远控软件主要是因为主流的远控软件如向日葵、todesk等均使用他们自家的公用服务器做中转，如果想要获得更高的服务质量就需要升级套餐。而这款软件可以使用自己搭建的服务器作为中继服务器，服务质量(如延迟、画质等方面)更有保障，且支持全平台。(其实，微软自带的远程桌面通过内网穿透后也可以达到类似的效果，不过仅限于windows设备使用)。因此，本教程主要介绍自己搭建服务器的用法。</p><h1 id="安装与使用教程" tabindex="-1"><a class="header-anchor" href="#安装与使用教程" aria-hidden="true">#</a> 安装与使用教程</h1><h2 id="前提" tabindex="-1"><a class="header-anchor" href="#前提" aria-hidden="true">#</a> 前提</h2><ol><li>需要一台有公网ip的机器(可以去阿里云、腾讯云等云服务器厂商购买)</li><li>服务器上安装好docker、docker-compose</li></ol><h2 id="安装" tabindex="-1"><a class="header-anchor" href="#安装" aria-hidden="true">#</a> 安装</h2><ol><li>云服务器安全组策略里放行所有端口<br> (不同服务器厂商操作不一，可自行查找设置)</li><li>云服务器开放防火墙端口</li></ol><p>:::note{title=&quot;端口说明&quot;} 默认情况下，hbbs 监听21115(tcp), 21116(tcp/udp), 21118(tcp)，hbbr 监听21117(tcp), 21119(tcp)。务必在防火墙开启这几个端口， 请注意21116同时要开启TCP和UDP。其中21115是hbbs用作NAT类型测试，21116/UDP是hbbs用作ID注册与心跳服务，21116/TCP是hbbs用作TCP打洞与连接服务，21117是hbbr用作中继服务, 21118和21119是为了支持网页客户端。如果您不需要网页客户端（21118，21119）支持，对应端口可以不开。 :::</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 1. 先查看已开放端口</span>
<span class="token function">sudo</span> firewall-cmd <span class="token parameter variable">--permanent</span> <span class="token parameter variable">--zone</span><span class="token operator">=</span>public --list-ports

<span class="token comment"># 2. 添加端以下口</span>
<span class="token function">sudo</span> firewall-cmd <span class="token parameter variable">--permanent</span> <span class="token parameter variable">--zone</span><span class="token operator">=</span>public --add-port <span class="token number">21115</span>/tcp
<span class="token function">sudo</span> firewall-cmd <span class="token parameter variable">--permanent</span> <span class="token parameter variable">--zone</span><span class="token operator">=</span>public --add-port <span class="token number">21116</span>/tcp
<span class="token function">sudo</span> firewall-cmd <span class="token parameter variable">--permanent</span> <span class="token parameter variable">--zone</span><span class="token operator">=</span>public --add-port <span class="token number">21117</span>/tcp
<span class="token function">sudo</span> firewall-cmd <span class="token parameter variable">--permanent</span> <span class="token parameter variable">--zone</span><span class="token operator">=</span>public --add-port <span class="token number">21118</span>/tcp
<span class="token function">sudo</span> firewall-cmd <span class="token parameter variable">--permanent</span> <span class="token parameter variable">--zone</span><span class="token operator">=</span>public --add-port <span class="token number">21119</span>/tcp
<span class="token function">sudo</span> firewall-cmd <span class="token parameter variable">--permanent</span> <span class="token parameter variable">--zone</span><span class="token operator">=</span>public --add-port <span class="token number">21116</span>/udp

<span class="token comment"># 3. 重新载入</span>
<span class="token function">sudo</span> firewall-cmd <span class="token parameter variable">--reload</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="3"><li>使用docker运行服务</li></ol><p>依次执行下面命令：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">mkdir</span> rustdesk
<span class="token builtin class-name">cd</span> rustdesk
<span class="token function">vim</span> docker-compose.yaml
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>其中，<code>docker-compose.yaml</code>内容如下：</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token key atrule">version</span><span class="token punctuation">:</span> <span class="token string">&#39;3.9&#39;</span>
<span class="token key atrule">services</span><span class="token punctuation">:</span>
    <span class="token key atrule">rustdesk-hbbs</span><span class="token punctuation">:</span>
        <span class="token key atrule">container_name</span><span class="token punctuation">:</span> rustdesk<span class="token punctuation">-</span>hbbs
        <span class="token key atrule">image</span><span class="token punctuation">:</span> rustdesk/rustdesk<span class="token punctuation">-</span>server
        <span class="token key atrule">hostname</span><span class="token punctuation">:</span> rustdesk<span class="token punctuation">-</span>host
        <span class="token key atrule">network_mode</span><span class="token punctuation">:</span> <span class="token string">&quot;host&quot;</span>
        <span class="token key atrule">ports</span><span class="token punctuation">:</span>
          <span class="token punctuation">-</span> <span class="token string">&quot;21115:21115&quot;</span>
          <span class="token punctuation">-</span> <span class="token string">&quot;21116:21116&quot;</span>
          <span class="token punctuation">-</span> <span class="token string">&quot;21116:21116/udp&quot;</span>
          <span class="token punctuation">-</span> <span class="token string">&quot;21118:21118&quot;</span>
        <span class="token key atrule">volumes</span><span class="token punctuation">:</span>
            <span class="token punctuation">-</span> <span class="token string">&#39;./data:/root&#39;</span>
        <span class="token key atrule">command</span><span class="token punctuation">:</span> <span class="token string">&quot;hbbs -r 1.2.3.4:21117&quot;</span> <span class="token comment"># 注意修改为你的云服务器公网ip</span>
        <span class="token key atrule">restart</span><span class="token punctuation">:</span> <span class="token string">&#39;unless-stopped&#39;</span>
    <span class="token key atrule">rustdesk-hbbr</span><span class="token punctuation">:</span>
        <span class="token key atrule">container_name</span><span class="token punctuation">:</span> rustdesk<span class="token punctuation">-</span>hbbr
        <span class="token key atrule">image</span><span class="token punctuation">:</span> rustdesk/rustdesk<span class="token punctuation">-</span>server
        <span class="token key atrule">hostname</span><span class="token punctuation">:</span> rustdesk<span class="token punctuation">-</span>host
        <span class="token key atrule">network_mode</span><span class="token punctuation">:</span> <span class="token string">&quot;host&quot;</span>
        <span class="token key atrule">ports</span><span class="token punctuation">:</span>
          <span class="token punctuation">-</span> <span class="token string">&quot;21117:21117&quot;</span>
          <span class="token punctuation">-</span> <span class="token string">&quot;21119:21119&quot;</span>
        <span class="token key atrule">volumes</span><span class="token punctuation">:</span>
            <span class="token punctuation">-</span> <span class="token string">&#39;./data:/root&#39;</span>
        <span class="token key atrule">command</span><span class="token punctuation">:</span> <span class="token string">&quot;hbbr&quot;</span>
        <span class="token key atrule">restart</span><span class="token punctuation">:</span> <span class="token string">&#39;unless-stopped&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>启动服务：<code>docker compose up -d</code><br> 第一次启动时，程序会自动拉取镜像并启动。</p><p title="tips: 常用服务管理命令">:::tip</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 启动服务</span>
<span class="token function">docker</span> compose up <span class="token parameter variable">-d</span>
<span class="token comment"># 停止服务</span>
<span class="token function">docker</span> compose down
<span class="token comment"># 重启服务</span>
<span class="token function">docker</span> compose restart
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>::: 4. 客户端连接设置<br> 所有客户端都要连接上中继服务器，下面以windows客户端为例演示(其他平台客户端操作类似)：</p><ul><li>首先，打开连接设置菜单</li></ul><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/1baeb54f81c9156d60645a49ac939a18.20221113201922.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ul><li>然后，填写ID服务器的ip或域名(就是你的云服务器ip)，其余的可不填(会自动推导).</li></ul><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/adc3a60ed90d2d84ce643bec82e242ba.20221113202133.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>当底部状态栏显示“就绪”时，说明连接中继服务器成功。</p><ul><li>最后，连接一台设备测试一下</li></ul><p>:::info{title=&quot;Ubuntu客户端设置&quot;} 由于我的另一台设备是Ubuntu的，直接连接可能会出现下面的错误：</p><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/1f7a1bce238c78bed89e6000beec1adb.image.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>下面介绍下被控端为Ubuntu时的额外设置：</p><ol><li>设置X11 display server</li></ol>`,28),g={href:"https://askubuntu.com/questions/1260142/ubuntu-set-default-login-desktop",target:"_blank",rel:"noopener noreferrer"},h=t(`<div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 查看当前拥有的桌面环境</span>
<span class="token function">ls</span> /usr/share/xsessions
<span class="token comment"># ubuntu.desktop  ubuntu-xorg.desktop</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>修改<code>/var/lib/AccountsService/users/&lt;your_username&gt;</code>文件内容:<br> 将XSession的值设置为上述桌面环境之一，名称务必保证正确，否则可能导致无法登录。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token punctuation">[</span>User<span class="token punctuation">]</span>
<span class="token assign-left variable">Session</span><span class="token operator">=</span>
<span class="token assign-left variable">Icon</span><span class="token operator">=</span>/home/kevin2li/.face
<span class="token assign-left variable">SystemAccount</span><span class="token operator">=</span>false
<span class="token assign-left variable">XSession</span><span class="token operator">=</span>ubuntu-xorg
<span class="token punctuation">[</span>InputSource0<span class="token punctuation">]</span>
<span class="token assign-left variable">xkb</span><span class="token operator">=</span>us
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>关闭Wayland<br> 在<code>/etc/gdm/custom.conf</code> 或 <code>/etc/gdm3/custom.conf</code>文件中设置如下参数：</li></ol><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token assign-left variable">WaylandEnable</span><span class="token operator">=</span>false
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>重启服务：<code>sudo systemctl restart gdm3</code> :::</p><p>连接成功截图：</p><figure><img src="https://minio.kevin2li.top/image-bed/vanblog/img/850ebf9563d75ef5e8b30bfa406d7181.20221114094153.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure>`,8);function f(_,y){const a=c("ExternalLinkIcon");return l(),p("div",null,[d,u,s("p",null,[n("RustDesk是一款开源的远程桌面软件，主要由rust语言开发，支持全平台(Windows、Max、Linux、Android等)，目前在"),s("a",m,[n("Github"),e(a)]),n("上已获得高达32k的star。"),k,n(" 官网："),s("a",b,[n("https://rustdesk.com/zh/"),e(a)])]),o(" more "),v,s("p",null,[n("参考："),s("a",g,[n("https://askubuntu.com/questions/1260142/ubuntu-set-default-login-desktop"),e(a)])]),h])}const q=i(r,[["render",f],["__file","开源远程桌面软件——RustDesk使用教程.html.vue"]]);export{q as default};
